mapper.select:
SELECT a.*, c.CPNY_LOCATION AS COMPANY_NAME, gvi.CONTENT AS ITEM_NAME_VI, gen.CONTENT AS ITEM_NAME_EN, gzh.CONTENT AS ITEM_NAME_ZH, gko.CONTENT AS ITEM_NAME_KO FROM AR_STA_ITEM_PARAM a LEFT JOIN HR_COMPANY c ON a.CPNY_ID = c.CPNY_ID LEFT JOIN SY_GLOBAL_NAME gvi ON a.ITEM_NO = gvi.NO AND gvi.LANGUAGE = 'vi' LEFT JOIN SY_GLOBAL_NAME gen ON a.ITEM_NO = gen.NO AND gen.LANGUAGE = 'en' LEFT JOIN SY_GLOBAL_NAME gzh ON a.ITEM_NO = gzh.NO AND gzh.LANGUAGE = 'zh' LEFT JOIN SY_GLOBAL_NAME gko ON a.ITEM_NO = gko.NO AND gko.LANGUAGE = 'ko' WHERE a.CPNY_ID = #{cpnyId}
AND (a.ITEM_NO LIKE '%' || #{searchText} || '%' OR gvi.CONTENT LIKE '%' || #{searchText} || '%')
ORDER BY a.ORDERNO, a.CAL_ORDER, a.PARAM_NO

mapper.insert:
INSERT INTO AR_STA_ITEM_PARAM (
    PARAM_NO, ITEM_NO, CPNY_ID, UNIT, MIN_UNIT, CAL_ORDER, 
    ACTIVITY, ORDERNO, MANAGE_FLAG, CREATE_DATE, CREATED_BY, CREATED_IP
) VALUES (
    #{paramNo}, #{itemNo}, #{cpnyId}, #{unit}, #{minUnit}, #{calOrder}, 
    #{activity}, #{orderno}, #{manageFlag}, SYSDATE, #{adminID}, #{adminIP}
)
